      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const tasks = [];
const createTask = (data) => {
  if (!data.title) return null;
  const task = { id: randomUUID(), ...data };
tasks.push(task);
return task;
};
module.exports = { createTask };"
